<style lang="scss"></style>
<template>
  <SpFinder
    ref="skuFinder"
    no-selection
    fixed-row-action
    url="/distributor/items"
    :hooks="{
      beforeSearch: beforeSearch,
      afterSearch: afterSearch
    }"
    :setting="setting"
  />
</template>

<script>
import { createSetting } from '@shopex/finder'
export default {
  name: '',
  props: {
    itemId: String,
    distributorId: String
  },
  data() {
    return {
      setting: createSetting({
        columns: [
          {
            name: '商品貨號',
            key: 'item_bn',
            width: 160
          },
          {
            name: '規格',
            key: 'item_spec_desc'
          },
          {
            name: '庫存',
            key: 'store',
            width: 100,
            showType: 'editable',
            componentProps: {
              change: async (v, row) => {
                await this.$api.marketing.updateDistributorItem({
                  distributor_id: this.distributorId,
                  item_id: row.item_id,
                  store: v
                })
                this.$refs.skuFinder.refresh()
              }
            }
          },
          {
            name: '商品價格（NT$）',
            key: 'price',
            width: 160,
            // render: (h, { row }) => h('span', {}, row.price / 100),
            showType: 'editable',
            componentProps: {
              change: async (v, row) => {
                await this.$api.marketing.updateDistributorItem({
                  distributor_id: this.distributorId,
                  item_id: row.item_id,
                  price: v * 100
                })
                this.$refs.skuFinder.refresh()
              }
            }
          },
          {
            name: '狀態',
            key: 'approve_status',
            render: (h, { row }) => h('span', {}, this.getApproveStatus(row.approve_status))
          },
          {
            name: '上下架操作',
            render: (h, { row }) =>
              h('el-switch', {
                props: {
                  'value': row.is_can_sale,
                  'active-value': true,
                  'inactive-value': false
                },
                on: {
                  change: async (e) => {
                    await this.$api.marketing.updateDistributorItem({
                      distributor_id: this.distributorId,
                      item_id: row.item_id,
                      is_can_sale: e
                    })
                    row.is_can_sale = e
                  }
                }
              })
          }
        ]
      })
    }
  },
  created() {},
  methods: {
    beforeSearch(params) {
      params = {
        ...params,
        is_sku: true,
        item_id: this.itemId,
        distributor_id: this.distributorId
      }
      return params
    },
    afterSearch(response) {
      const { list } = response.data.data

      list.forEach((item) => {
        item.price = item.price / 100
      })
      return list
    },
    getApproveStatus(status) {
      const approveStatus = {
        onsale: '前台可銷售',
        offline_sale: '前台不顯示'
      }
      return approveStatus[status] || '不可銷售'
    }
  }
}
</script>
